const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const PROJECT = '/mnt/d/NAS-DATA/antenna-engine';
const output = $('Gen Sidebar').item.json.output || '';

let result = 'LGTM - no files written';
if (!output.includes('LGTM')) {
  // Extract and write code blocks
  const blocks = [...output.matchAll(/```(?:tsx?)\n([\s\S]*?)```/g)];
  result = `Found ${blocks.length} code blocks`;
}

// TSC check
let tsc = '';
try {
  tsc = execSync('npx tsc --noEmit 2>&1', { cwd: PROJECT, timeout: 60000 }).toString();
  if (!tsc.trim()) tsc = 'OK';
} catch (e) {
  tsc = e.stdout?.toString() || e.message;
}

// Git commit
let git = '';
if (!tsc.includes('error TS')) {
  try {
    execSync('git add -A && git commit -m "style: redesign sidebar — compact, collapsible sections"', { cwd: PROJECT });
    git = 'Committed';
  } catch (e) {
    git = e.message;
  }
}

return [{ json: { result, tsc, git } }];
